  ('disabled-57f41407-moex-00093', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於刑事程序中之告訴，下列敘述何者錯誤？', '["告訴乃論之罪，對於共犯之一人告訴者，其效力及於其他共犯", "撤回告訴之人，不得再行告訴，但對同一案件之告訴乃論之罪，仍得再 行告發", "告訴乃論之罪，對於共犯之一人撤回告訴者，其效力及於其他共犯", "告訴乃論之罪，告訴人於第一審辯論終結前，得撤回其告訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00094', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於緩起訴，下列敘述何者正確？', '["緩起訴期間內，對告訴乃論之罪，犯罪直接被害人得提起自訴", "檢察官為緩起訴處分時，應得被告之同意，始得命被告向被害人支付一 定金額", "檢察官為緩起訴處分時，應得被告之同意，始得命被告向被害人道歉", "緩起訴期間內，被告犯過失傷害罪而被提起公訴時，得撤銷原緩起訴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00095', 'disabled-57f41407', 'disabled-57f41407-moex-114-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '刑事訴訟中關於告訴人不服駁回再議之處分時，聲請法院准許提起自訴之 制度（下稱聲請准許提起自訴），下列敘述何者錯誤？', '["聲請准許提起自訴時，應委任律師行之", "依法已不得提起自訴者，原則上不得聲請准許提起自訴", "聲請准許提起自訴之裁定，法院應以合議行之", "被告對於准許提起自訴之裁定，不得提起抗告。駁回之裁定，得抗告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:34+00:00", "source_pdf_sha1": "f8c4261c4045", "answer_pdf_sha1": "535045d9caaa", "source_family": "moex-gov-tw", "moex": {"exam_code": "114040", "c": "504", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "114", "exam_name": "114年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
